//! `0q` — gnosis-antiqueue CLI.
//!
//! Subcommands:
//! * `bench`   — run the antiqueue vs mock-rabbit bench end-to-end.
//! * `produce` — publish N synthetic messages on a routing key.
//! * `consume` — declare a consumer and print arrivals until N delivered.
//! * `tail`    — tail telemetry from a process-local broker (smoke).
//!
//! All subcommands operate on an in-process broker. There is no network
//! protocol here today — the AMQP shape is a *programming-model* mapping
//! (see lib.rs), and the bench is the receipts.

use std::sync::atomic::{AtomicUsize, Ordering};
use std::sync::Arc;
use std::time::{Duration, Instant};

use gnosis_antiqueue::mock_rabbit::read_u128_le;
use gnosis_antiqueue::{mock_rabbit, Broker, ExchangeKind, Message, Stoplight, StoplightExt};

fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 2 {
        print_usage();
        std::process::exit(2);
    }
    match args[1].as_str() {
        "bench" => cmd_bench(&args[2..]),
        "produce" => cmd_produce(&args[2..]),
        "consume" => cmd_consume(&args[2..]),
        "tail" => cmd_tail(),
        "help" | "-h" | "--help" => print_usage(),
        other => {
            eprintln!("0q: unknown subcommand `{other}`");
            print_usage();
            std::process::exit(2);
        }
    }
}

fn print_usage() {
    eprintln!(
        "0q -- gnosis-antiqueue CLI\n\
         \n\
         USAGE:\n  \
           0q <subcommand> [args]\n\
         \n\
         SUBCOMMANDS:\n  \
           bench [N]                    run the antiqueue vs mock-rabbit bench (default N=50000)\n  \
           produce <queue> <N>          publish N messages to <queue>\n  \
           consume <queue> <N>          consume up to N messages from <queue>\n  \
           tail                         print telemetry snapshots until ctrl-c\n  \
           help                         show this message\n",
    );
}

// ─────────────────────────────────────────────────────────────────────
// bench
// ─────────────────────────────────────────────────────────────────────

fn cmd_bench(rest: &[String]) {
    let total: usize = rest.first().and_then(|s| s.parse().ok()).unwrap_or(50_000);
    let consumers: usize = 20;
    let service = Duration::from_millis(1);

    println!("0q bench: {total} messages, {consumers} consumers, prefetch=1, service=1ms");
    println!("=================================================================");

    // ── Mock RabbitMQ baseline ────────────────────────────────────────
    let rabbit_start = Instant::now();
    let rabbit_lats = run_rabbit(total, consumers, service);
    let rabbit_walk = rabbit_start.elapsed();
    let rabbit_p50 = percentile(&rabbit_lats, 50);
    let rabbit_p99 = percentile(&rabbit_lats, 99);

    // ── gnosis-antiqueue ──────────────────────────────────────────────
    let aq_start = Instant::now();
    let (aq_lats, aq_peak, aq_delivered) = run_antiqueue(total, consumers, service);
    let aq_walk = aq_start.elapsed();
    let aq_p50 = percentile(&aq_lats, 50);
    let aq_p99 = percentile(&aq_lats, 99);

    println!();
    println!("  Mock RabbitMQ (Mutex<VecDeque> + Condvar, FIFO, prefetch=1)");
    println!(
        "    wall-clock:   {:>10.2} ms",
        rabbit_walk.as_secs_f64() * 1000.0
    );
    println!(
        "    p50 latency:  {:>10.2} us",
        rabbit_p50.as_secs_f64() * 1_000_000.0
    );
    println!(
        "    p99 latency:  {:>10.2} us",
        rabbit_p99.as_secs_f64() * 1_000_000.0
    );
    println!();
    println!("  gnosis-antiqueue (Stoplight corridor, no buffer)");
    println!(
        "    wall-clock:   {:>10.2} ms",
        aq_walk.as_secs_f64() * 1000.0
    );
    println!(
        "    p50 latency:  {:>10.2} us",
        aq_p50.as_secs_f64() * 1_000_000.0
    );
    println!(
        "    p99 latency:  {:>10.2} us",
        aq_p99.as_secs_f64() * 1_000_000.0
    );
    println!("    peak depth:   {:>10}", aq_peak);
    println!("    delivered:    {:>10}/{total}", aq_delivered);

    let p99_speedup = rabbit_p99.as_nanos() as f64 / aq_p99.as_nanos().max(1) as f64;
    println!();
    println!("  p99 speedup: {p99_speedup:.2}x  (target: >=10x)");
    println!(
        "  DoD: {}",
        if p99_speedup >= 10.0 && aq_delivered == total && aq_peak <= consumers {
            "PASS"
        } else {
            "MEASURED"
        }
    );
}

fn run_rabbit(total: usize, consumers: usize, service: Duration) -> Vec<Duration> {
    let broker = mock_rabbit::MockBroker::new();
    broker.declare_queue("tasks");
    let epoch = Instant::now();
    let b2 = Arc::clone(&broker);
    let consumer_handle =
        std::thread::spawn(move || b2.consume_blocking("tasks", consumers, service, total, epoch));
    for _ in 0..total {
        let ns = epoch.elapsed().as_nanos();
        broker.publish("tasks", Message::new("tasks", ns.to_le_bytes().to_vec()));
    }
    consumer_handle.join().unwrap()
}

fn run_antiqueue(
    total: usize,
    consumers: usize,
    service: Duration,
) -> (Vec<Duration>, usize, usize) {
    let broker = Broker::with_tick(Duration::from_micros(50));
    let latencies = Arc::new(std::sync::Mutex::new(Vec::with_capacity(total)));
    let epoch = Instant::now();

    for i in 0..consumers {
        let lats = Arc::clone(&latencies);
        broker.declare_consumer(
            &format!("worker.{i}"),
            // cycle=consumers, green=1; per Lean arrivalPhase(i) =
            // (i + offset) mod consumers < 1, so offset = (consumers - i)
            // mod consumers gives task i its own green slot.
            Stoplight::resting(consumers as u32, 1, ((consumers - i) % consumers) as u32),
            move |msg| {
                let svc_start = Instant::now();
                let deadline = svc_start + service;
                while Instant::now() < deadline {
                    std::hint::spin_loop();
                }
                let enq_ns = read_u128_le(&msg.body);
                let now_ns = epoch.elapsed().as_nanos();
                lats.lock().unwrap().push(Duration::from_nanos(
                    now_ns.saturating_sub(enq_ns).min(u64::MAX as u128) as u64,
                ));
                Ok(())
            },
        );
    }
    let p = broker.producer("");
    let delivered = Arc::new(AtomicUsize::new(0));
    let d2 = Arc::clone(&delivered);

    std::thread::scope(|s| {
        let per_worker = total / consumers;
        let leftover = total - per_worker * consumers;
        for i in 0..consumers {
            let p = p.clone();
            let d = Arc::clone(&d2);
            let count = if i == 0 {
                per_worker + leftover
            } else {
                per_worker
            };
            s.spawn(move || {
                for _ in 0..count {
                    let ns = epoch.elapsed().as_nanos();
                    if p.publish(&format!("worker.{i}"), ns.to_le_bytes().to_vec())
                        .is_ok()
                    {
                        d.fetch_add(1, Ordering::Relaxed);
                    }
                }
            });
        }
    });

    let lats = std::mem::take(&mut *latencies.lock().unwrap());
    let telemetry = broker.telemetry();
    (
        lats,
        telemetry.peak_in_flight,
        delivered.load(Ordering::Acquire),
    )
}

fn percentile(samples: &[Duration], p: u32) -> Duration {
    if samples.is_empty() {
        return Duration::ZERO;
    }
    let mut s: Vec<Duration> = samples.to_vec();
    s.sort_unstable();
    let idx = ((p as usize) * s.len() / 100).min(s.len() - 1);
    s[idx]
}

// ─────────────────────────────────────────────────────────────────────
// produce / consume / tail
// ─────────────────────────────────────────────────────────────────────

fn cmd_produce(rest: &[String]) {
    if rest.len() < 2 {
        eprintln!("0q produce <queue> <N>");
        std::process::exit(2);
    }
    let queue = &rest[0];
    let n: usize = rest[1].parse().unwrap_or(1);
    let broker = Broker::local();
    broker.declare_exchange("", ExchangeKind::Direct);
    // Without a consumer the broker drops; we still want to demo the
    // produce path so we attach a no-op consumer.
    let qq = queue.clone();
    broker.declare_consumer(&qq, Stoplight::open(1), |_msg| Ok(()));
    let p = broker.producer("");
    for i in 0..n {
        let body = format!("msg-{i}").into_bytes();
        p.publish(queue, body).unwrap();
    }
    let t = broker.telemetry();
    println!(
        "produced: {} delivered: {} dropped: {}",
        t.published, t.delivered, t.dropped
    );
}

fn cmd_consume(rest: &[String]) {
    if rest.len() < 2 {
        eprintln!("0q consume <queue> <N>");
        std::process::exit(2);
    }
    let queue = rest[0].clone();
    let n: usize = rest[1].parse().unwrap_or(1);
    let broker = Broker::local();
    let counter = Arc::new(AtomicUsize::new(0));
    let c2 = Arc::clone(&counter);
    let q2 = queue.clone();
    broker.declare_consumer(&queue, Stoplight::open(1), move |msg| {
        let n = c2.fetch_add(1, Ordering::Relaxed);
        println!("[{q2}] #{n}: {} bytes", msg.body.len());
        Ok(())
    });
    let p = broker.producer("");
    for i in 0..n {
        p.publish(&queue, format!("auto-{i}").into_bytes()).unwrap();
    }
    println!("consumed: {} of {}", counter.load(Ordering::Acquire), n);
}

fn cmd_tail() {
    let broker = Broker::local();
    broker.declare_consumer("tail.demo", Stoplight::open(4), |_| Ok(()));
    let p = broker.producer("");
    let start = Instant::now();
    let mut i = 0usize;
    while start.elapsed() < Duration::from_secs(2) {
        p.publish("tail.demo", i.to_string().into_bytes()).ok();
        i += 1;
        if i % 1000 == 0 {
            let t = broker.telemetry();
            println!(
                "t={:>5}ms  published={} delivered={} peak_depth={}",
                start.elapsed().as_millis(),
                t.published,
                t.delivered,
                t.peak_in_flight,
            );
        }
    }
}
